fixed_code:
use std::thread_local;

fn main() {
    thread_local! {
        static MY_TLS: String = String::from("hello");
    }

    let handle = std::thread::spawn(|| {
        MY_TLS.with(|s| println!("{}", s));
    });

    handle.join().unwrap();
}

